// PayPal βÜî Giro-VerknΟΦpfung βÄî robustes Matching mit eindeutigen Merkmalen.
//
// Hintergrund: PayPal-Zahlungen belasten das Girokonto per SEPA-Lastschrift.
// Auf dem Kontoauszug erscheint dann eine Buchung an "PayPal Europe βÄΠ" mit
// dem Verwendungszweck ". Ihr Einkauf bei {HΟΛndler}". Ziel: jede konkrete
// PayPal-Buchung (aus dem PayPal-CSV) der passenden Giro-Belastung zuordnen βÄ™
// ohne wilde FehlverknΟΦpfungen.
//
// Eindeutige Merkmale (statt nur Betrag+Datum):
//  1. GlΟΛubiger-ID: PayPals SEPA-Creditor-ID in DE ist fix βÜ£ 100 % PayPal.
//  2. EmpfΟΛnger/Text enthΟΛlt "paypal" βÜ£ PayPal-Lastschrift.
//  3. HΟΛndlername aus dem PayPal-CSV taucht wΟΕrtlich im Giro-Verwendungszweck
//     auf ("Ihr Einkauf bei {HΟΛndler}") βÜ£ unterscheidet gleich-hohe Buchungen.

// PayPal (Europe) S.Ο† r.l. et Cie, S.C.A. βÄî feste GlΟΛubiger-ID in Deutschland.
export const PAYPAL_CREDITOR_ID = "LU96ZZZ0000000000000000058";

const normCreditor = s => (s || "").replace(/\s+/g, "").toUpperCase();

// Generische WΟΕrter, die NICHT als HΟΛndlername zΟΛhlen (PayPal-Boilerplate,
// Rechtsformen, Verwendungszweck-Floskeln).
const STOP = new Set([
  "paypal", "europe", "sarl", "cie", "sca", "scrl", "luxembourg",
  "gmbh", "ag", "kg", "ohg", "ltd", "inc", "limited", "co", "company",
  "ihr", "einkauf", "bei", "ein", "kauf", "der", "die", "das", "und",
  "com", "www", "http", "https", "payment", "zahlung", "ref", "kd",
  "mandat", "mandatsref", "glaeubiger", "verwendungszweck",
  // Finanzblick-PayPal-Floskeln (Status / Gegenbuchungen), kein HΟΛndlername:
  "successful", "pending", "completed", "rechnungs", "nr", "rechnungsnr",
  "sonstige", "einnahmen", "abbuchung", "konto", "service", "services",
]);

const norm = s =>
  (s || "")
    .toLowerCase()
    .normalize("NFKD")
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();

const tokens = s => norm(s).split(" ").filter(t => t.length >= 3 && !STOP.has(t));

// Ist die Giro-Buchung eine PayPal-Lastschrift?
export function isPayPalGiroTx(tx) {
  if (tx && tx._creditorId && normCreditor(tx._creditorId) === PAYPAL_CREDITOR_ID) return true;
  const d = (tx?.desc || "").toLowerCase();
  return d.includes("paypal") || /\bpp\.\s*\d/.test(d) || /\bpp\.\b/.test(d);
}

// HΟΛndlername aus einer PayPal-CSV-Zeile. Bevorzugt einen angereicherten Namen
// (aus der zugehΟΕrigen Kaufzeile bei βÄûPayPal +30", siehe enrichPayPalMerchants),
// dann das separate EmpfΟΛnger-Feld (_recipient), sonst die erste
// Beschreibungs-Komponente.
export function payPalMerchant(row) {
  if (row?._enrichedMerchant) return row._enrichedMerchant;
  const raw = (row?._recipient || (row?.desc || "").split(" ¬Ζ ")[0]);
  return raw
    .split(" βÄ™ ")[0]
    .replace(/\{[^}]{0,300}\}/g, "")
    .trim();
}

// βÄûPayPal Bezahlen nach 30 Tagen": Finanzblick legt zwei Ausgaben-Zeilen an βÄî
// den Kauf (mit echtem HΟΛndler) und ~30 Tage spΟΛter die Abbuchung ΟΦber
// βÄûPayPal (Europe) βÄΠ" OHNE HΟΛndler. Diese Funktion reichert solche hΟΛndlerlosen
// Abbuchungen mit dem HΟΛndler der passenden Kaufzeile an (gleicher Betrag,
// 24βÄ™40 Tage frΟΦher, eindeutiger HΟΛndler). Gibt eine neue Zeilen-Liste zurΟΦck
// (Reihenfolge/LΟΛnge unverΟΛndert βÜ£ Indizes bleiben gΟΦltig).
export function enrichPayPalMerchants(rows) {
  const generic = m => tokens(m).length === 0; // nur Floskeln/Rechtsform βÜ£ kein echter HΟΛndler
  const DAY = 86400000;
  const meta = rows.map(r => {
    const amt = r.amount ?? r.totalAmount ?? 0;
    return {
      cents: Math.round(Math.abs(amt) * 100),
      date: new Date(r.isoDate || r.date).getTime(),
      merchant: payPalMerchant(r),
      income: amt > 0,
    };
  });
  const refs = rows.map(r => payPalRefTokens(r));    // Referenzkennungen je Zeile
  const enriched = new Array(rows.length).fill(null);
  const kind = new Array(rows.length).fill(null);     // "plus30" | "withdrawal"
  const isLeg = new Array(rows.length).fill(false);   // Quell-Leg βÜ£ vom Giro-Matching ausschlieΟüen
  const legFps = new Array(rows.length).fill(null);   // Fingerprints der Quell-Legs (zum Mit-VerknΟΦpfen)
  rows.forEach((r, i) => {
    const cur = meta[i];
    if (!generic(cur.merchant)) return;
    // Quelle: gleiches Vorzeichen, gleicher Betrag, echter HΟΛndler, im Fenster.
    // Fenster bewusst weit gespannt (zusammenhΟΛngende Buchungen liegen je nach
    // Abrechnungslauf/Wochenende unterschiedlich weit auseinander):
    //  - Ausgabe (Lastschrift): Kauf 18βÄ™45 Tage frΟΦher (βÄûPayPal +30").
    //  - Einnahme (Auszahlung): Quell-Eingang/Erstattung 0βÄ™16 Tage frΟΦher.
    const window = cur.income ? [0, 16] : [18, 45];
    let sources = meta
      .map((o, j) => ({ o, j }))
      .filter(({ o, j }) => {
        if (j === i || o.income !== cur.income || o.cents !== cur.cents || generic(o.merchant)) return false;
        const dd = (cur.date - o.date) / DAY; // Quelle liegt VOR der generischen Buchung
        return dd >= window[0] && dd <= window[1];
      });
    if (!sources.length) return;
    let names = [...new Set(sources.map(s => s.o.merchant))];
    if (names.length !== 1) {
      // Mehrdeutig nach Betrag/Zeit βÜ£ gemeinsame Referenz (Rechnungs-/Bestell-/
      // Transaktionsnr.) als zusΟΛtzliches Unterscheidungsmerkmal: teilen sich
      // generische Buchung und genau EIN Kauf eine Kennung, ist die Quelle klar.
      const myRef = refs[i];
      if (myRef.size) {
        const refHits = sources.filter(s => [...myRef].some(t => refs[s.j].has(t)));
        const refNames = [...new Set(refHits.map(s => s.o.merchant))];
        if (refNames.length === 1) { sources = refHits; names = refNames; }
      }
    }
    if (names.length !== 1) return; // weiterhin mehrdeutig βÜ£ nicht anreichern
    enriched[i] = names[0];
    kind[i] = cur.income ? "withdrawal" : "plus30";
    // Quell-Leg markieren: hat keine eigene Giro-Buchung (lΟΛuft ΟΦber DIESE
    // generische Abbuchung/Auszahlung) βÜ£ vom Giro-Matching ausschlieΟüen.
    legFps[i] = sources.map(s => rows[s.j].fp).filter(Boolean);
    sources.forEach(({ j }) => { isLeg[j] = true; });
  });
  return rows.map((r, i) => {
    let out = r;
    if (enriched[i]) out = { ...out, _enrichedMerchant: enriched[i],
      ...(kind[i] === "withdrawal" ? { _enrichedWithdrawal: true } : { _enrichedPlus30: true }),
      ...(legFps[i] && legFps[i].length ? { _legSourceFps: legFps[i] } : {}) };
    if (isLeg[i]) out = { ...out, _internalLeg: true };
    return out;
  });
}

// Ist diese geparste CSV ein PayPal-AktivitΟΛts-Export? Der Finanzblick-
// PayPal-Export wird als Format "Finanzblick" erkannt (gleicher Spaltenkopf wie
// eine Bank-CSV), trΟΛgt aber im Konto-Feld βÄûPayPal (βÄΠ)". Daher am Inhalt prΟΦfen.
export function looksLikePayPalCsv(format, rows) {
  if (/paypal/i.test(format || "")) return true;
  if (!rows || !rows.length) return false;
  const ppKonto = rows.filter(r => /paypal/i.test(r._konto || "")).length;
  return ppKonto > rows.length * 0.5;
}

// Entfernt die internen PayPal-Gegenbuchungen: Zeilen OHNE EmpfΟΛnger, die eine
// gleich hohe Buchung mit GEGENVORZEICHEN in ¬±3 Tagen spiegeln (die βÄûFinanzierung"
// jeder Zahlung βÄî bei Ausgaben als +X, bei Einnahmen/Erstattungen als βà£X). Echte
// Buchungen mit EmpfΟΛnger bleiben erhalten.
export function dropPayPalCounterBookings(rows) {
  const DAY = 86400000;
  const byKey = new Map(); // `${+|-}${cents}` βÜ£ [Zeitstempel]
  rows.forEach(r => {
    const a = r.amount ?? r.totalAmount ?? 0;
    if (a === 0) return;
    const key = (a > 0 ? "+" : "-") + Math.round(Math.abs(a) * 100);
    if (!byKey.has(key)) byKey.set(key, []);
    byKey.get(key).push(new Date(r.isoDate || r.date).getTime());
  });
  return rows.filter(r => {
    const a = r.amount ?? r.totalAmount ?? 0;
    if (a === 0) return true;
    if (r._recipient) return true;  // echte Buchung mit EmpfΟΛnger behalten
    // Gegenbuchung: gibt es eine Gegenvorzeichen-Buchung gleichen Betrags in ¬±3 Tagen?
    const oppKey = (a > 0 ? "-" : "+") + Math.round(Math.abs(a) * 100);
    const dates = byKey.get(oppKey) || [];
    const rd = new Date(r.isoDate || r.date).getTime();
    const isCounter = dates.some(d => Math.abs(d - rd) <= 3 * DAY);
    return !isCounter;              // Gegenbuchung βÜ£ entfernen
  });
}

// Erkennt RΟΦckerstattungen unter den Einnahmen: ein PayPal-Eingang ist eine
// Erstattung, wenn (a) der Text ein Erstattungs-SchlΟΦsselwort enthΟΛlt oder
// (b) der HΟΛndler ein Ausgaben-HΟΛndler ist und es eine gleich hohe Ausgabe gibt
// (z.B. Apple/AliExpress/COMTRADA erstatten). Markiert die Zeile mit _isRefund
// und βÄ™ falls gefunden βÄ™ _refundOf (die zugehΟΕrige frΟΦhere Ausgabe).
const REFUND_RE = /reverse payment|credit has been processed|claim is now closed|dispute|erstattung|r[ΟΦu]ckerstattung|r[ΟΦu]ckzahlung|refund|reversal|storno|gutschrift/i;
function merchantsSimilar(a, b) {
  const tb = new Set(tokens(b));
  return tokens(a).some(t => tb.has(t));
}

// Stabile Referenzkennungen einer Zeile (Rechnungs-/Bestell-/Invoice-Nr,
// PayPal-Transaktionscodes). Dienen dem Abgleich Erstattung βÜî Originalzahlung
// auch bei TEILerstattung, wo der Betrag NICHT mehr als SchlΟΦssel taugt:
//  - PayPal-Direktexport: refCode (Referenztransaktionscode) der Erstattung ist
//    der txCode (Transaktionscode) der ursprΟΦnglichen Zahlung βÜ£ eindeutig.
//  - Finanzblick u.a.: Rechnungs-/Bestell-/Invoice-Nr im Text, Amazon-Bestellnr.
const REF_PATTERNS = [
  /Rechnungs?-?\s*Nr[.:]?\s*([A-Z0-9][A-Z0-9-]{4,})/ig,
  /Invoice[-\s]?(?:Nr|No|#)?[.:]?\s*([A-Z0-9][A-Z0-9-]{4,})/ig,
  /Bestell(?:nummer|nr|ung)?[.:]?\s*([A-Z0-9][A-Z0-9-]{4,})/ig,
  /\b(\d{3}-\d{7}-\d{7})\b/g,            // Amazon-Bestellnr
  /\b(PP\.[A-Z0-9]+\.PP)\b/ig,
  /\b(PAYID-[A-Z0-9]+)\b/ig,
  /\b(T-[A-Z0-9]{10,})\b/ig,
];
export function payPalRefTokens(row) {
  const set = new Set();
  const code = v => { const s = String(v || "").trim().toUpperCase(); if (s.length >= 5) set.add(s); };
  code(row?.txCode);
  code(row?.refCode);
  const src = `${row?.rowType || ""} ${row?.desc || ""} ${row?._detailNote || ""}`;
  REF_PATTERNS.forEach(re => { re.lastIndex = 0; let m; while ((m = re.exec(src))) set.add((m[1] || m[0]).toUpperCase()); });
  return set;
}

export function detectPayPalRefunds(rows) {
  const DAY = 86400000;
  const expenses = rows
    .filter(r => (r.amount ?? r.totalAmount ?? 0) < 0)
    .map(e => ({
      e,
      cents: Math.round(Math.abs(e.amount ?? e.totalAmount ?? 0) * 100),
      t: new Date(e.isoDate || e.date).getTime(),
      merch: payPalMerchant(e),
      ref: payPalRefTokens(e),
    }));
  return rows.map(r => {
    const a = r.amount ?? r.totalAmount ?? 0;
    if (a <= 0) return r; // nur Einnahmen prΟΦfen
    if (r._enrichedWithdrawal) return r; // Auszahlung einer Erstattung ist selbst keine Erstattung
    const merch = payPalMerchant(r);
    const keyword = REFUND_RE.test(r.desc || "");
    const cents = Math.round(a * 100);
    const rd = new Date(r.isoDate || r.date).getTime();
    let best = null, partial = false;
    // 1) Eindeutige Referenz (Rechnungs-/Transaktionsnr.): matcht auch, wenn der
    //    erstattete Betrag KLEINER ist als die Ausgabe (Teilerstattung). Die
    //    Ausgabe muss βâΞ Erstattung sein und (typisch) frΟΦher liegen.
    const myRef = payPalRefTokens(r);
    if (myRef.size) {
      const refHit = expenses
        .filter(x => x.cents >= cents && x.t <= rd + 3 * DAY && [...myRef].some(tok => x.ref.has(tok)))
        .sort((x, y) => Math.abs(x.t - rd) - Math.abs(y.t - rd))[0];
      if (refHit) { best = refHit.e; partial = refHit.cents !== cents; }
    }
    // 2) Fallback: gleicher Betrag + ΟΛhnlicher HΟΛndler (bisheriges Verhalten).
    if (!best && merch && tokens(merch).length) {
      best = expenses
        .filter(x => x.cents === cents && merchantsSimilar(merch, x.merch))
        .map(x => ({ e: x.e, dd: Math.abs(x.t - rd) }))
        .sort((x, y) => x.dd - y.dd)[0]?.e || null;
    }
    if (!keyword && !best) return r;
    return {
      ...r, _isRefund: true,
      ...(partial ? { _partialRefund: true } : {}),
      ...(best ? { _refundOf: { date: best.isoDate, amount: best.amount ?? -(best.totalAmount || 0), merchant: payPalMerchant(best), ...(partial ? { partial: true } : {}) } } : {}),
    };
  });
}

// Reconciliation nach allen Filterschritten: βÄûinterne Legs" reparieren, deren
// Auszahlung nicht ΟΦberlebt hat. Eine Quell-Erstattung wird nur dann vom
// Giro-Matching ausgeschlossen (_internalLeg), wenn es TATSΟ³CHLICH noch eine
// Auszahlungs-Zeile gibt, die per _legSourceFps darauf verweist. Wurde diese
// Auszahlung zwischenzeitlich entfernt (z.B. als interne Gegenbuchung), wΟΛre das
// Leg sonst verwaist: Hinweis βÄûβÜ£ aufs Giro ausgezahlt", obwohl es keine
// Auszahlung mehr gibt, UND fΟΛlschlich nicht zuordenbar. Dann: Flag aufheben,
// damit die Erstattung wieder normal der Giro-Gutschrift zugeordnet werden kann.
// Spiegelbildlich: zeigt _legSourceFps auf entfernte Zeilen, wird es bereinigt.
export function reconcilePayPalLegs(rows) {
  const present = new Set(rows.map(r => r.fp).filter(Boolean));
  const referenced = new Set();
  rows.forEach(r => (r._legSourceFps || []).forEach(fp => { if (present.has(fp)) referenced.add(fp); }));
  return rows.map(r => {
    let out = r;
    if (out._internalLeg && (!out.fp || !referenced.has(out.fp))) {
      const { _internalLeg, ...rest } = out; out = rest; // verwaistes Leg βÜ£ normale Buchung
    }
    if (out._legSourceFps) {
      const fps = out._legSourceFps.filter(fp => present.has(fp));
      if (fps.length !== out._legSourceFps.length) {
        if (fps.length) out = { ...out, _legSourceFps: fps };
        else { const { _legSourceFps, ...rest } = out; out = rest; }
      }
    }
    return out;
  });
}

// Steckt der HΟΛndlername im Giro-Verwendungszweck? Token-basiert, damit
// "REWE SAGT DANKE" βÜî "Rewe" trotzdem greift, aber Floskeln nicht fΟΛlschlich
// matchen. Match, wenn ein signifikantes HΟΛndler-Token (βâΞ4 Zeichen Teilstring,
// oder exaktes Token βâΞ3) im Giro-Text vorkommt.
export function merchantMatchesGiro(merchant, giroDesc) {
  const gNorm = norm(giroDesc);
  if (!gNorm) return false;
  const gToks = new Set(tokens(giroDesc));
  const mToks = tokens(merchant);
  if (!mToks.length) return false;
  return mToks.some(t => (t.length >= 4 && gNorm.includes(t)) || gToks.has(t));
}

// Erwartete zeitliche Lage der Giro-Lastschrift relativ zur PayPal-Buchung.
//  - "sofort": Standard βÄî Giro wird wenige Tage nach der PayPal-Buchung belastet.
//  - "plus30": βÄûPayPal Bezahlen nach 30 Tagen" βÄî Belastung ~30 Tage spΟΛter.
//  - "unklar": dazwischen / weiter weg βÜ£ bei wiederkehrenden BetrΟΛgen meist der
//    falsche Monat.
// signedDays = Giro-Datum βà£ PayPal-Datum (positiv = Giro spΟΛter, der Normalfall).
export const TIMING = { SOFORT_MIN: -2, SOFORT_MAX: 10, PLUS30_MIN: 24, PLUS30_MAX: 38 };
export function timingTier(signedDays) {
  if (signedDays >= TIMING.SOFORT_MIN && signedDays <= TIMING.SOFORT_MAX) return "sofort";
  if (signedDays >= TIMING.PLUS30_MIN && signedDays <= TIMING.PLUS30_MAX) return "plus30";
  return "unklar";
}

// Bewertet ein Kandidatenpaar (PayPal-Zeile βÜî Giro-Buchung). Gibt null zurΟΦck,
// wenn es kein Kandidat ist (falsches Vorzeichen, falscher Betrag, kein PayPal,
// auΟüerhalb Fenster). Paart symmetrisch: PayPal-Ausgabe βÜî Giro-Lastschrift UND
// PayPal-Eingang βÜî Giro-Gutschrift (βÄûABBUCHUNG VOM PAYPAL-KONTO").
export function scoreMatch(row, giroTx, linkDays) {
  const rowAmt = row.amount ?? row.totalAmount ?? 0;
  const rowIsIncome = rowAmt > 0;
  // Giro-Vorzeichen: _csvType bevorzugen (CSV speichert totalAmount als Betrag),
  // sonst aus dem Vorzeichen von totalAmount (manuelle Buchungen sind signiert).
  const giroIsIncome = giroTx._csvType ? giroTx._csvType === "income" : (giroTx.totalAmount || 0) > 0;
  // Normalfall: Vorzeichen muss passen (PayPal-Ausgabe βÜî Giro-Lastschrift,
  // PayPal-Eingang βÜî Giro-Gutschrift). Sonderfall βÄûErstattung": eine PayPal-
  // Erstattung (Eingang) gehΟΕrt zur ursprΟΦnglichen Giro-LASTSCHRIFT (Ausgang) βÄî
  // gegenlΟΛufige Vorzeichen. Nur mit klarem HΟΛndlerbezug und nur als Vorschlag
  // (nie Auto-Link, siehe assignPayPalLinks).
  const refundVsDebit = !!row._isRefund && rowIsIncome && !giroIsIncome;
  if (rowIsIncome !== giroIsIncome && !refundVsDebit) return null;
  const absAmt = Math.abs(rowAmt);
  if (Math.round(Math.abs(giroTx.totalAmount || 0) * 100) !== Math.round(absAmt * 100)) return null;
  if (!isPayPalGiroTx(giroTx)) return null;
  const rDate = new Date(row.isoDate || row.date).getTime();
  const tDate = new Date(giroTx.date).getTime();
  const signedDays = Math.round((tDate - rDate) / 86400000);
  const diffDays = Math.abs(signedDays);
  if (diffDays > linkDays) return null;
  // Gemeinsamkeit ΟΦber den HΟΛndlernamen ODER eine geteilte Referenzkennung
  // (Rechnungs-/Bestell-/Transaktionsnr.). Letztere verbindet auch zeitlich weit
  // auseinanderliegende Buchungen eindeutig (z.B. gleiche Amazon-Bestellnr.).
  const refMatch = (() => {
    const a = payPalRefTokens(row);
    if (!a.size) return false;
    const b = payPalRefTokens({ desc: giroTx.desc, _detailNote: giroTx.note });
    return [...a].some(t => b.has(t));
  })();
  const merchantMatch = merchantMatchesGiro(payPalMerchant(row), giroTx.desc) || refMatch;
  if (refundVsDebit && !merchantMatch) return null; // ohne HΟΛndlerbezug zu unsicher
  const tier = timingTier(signedDays);
  // Score nur als Sortier-Fallback; maΟügeblich ist die Konfidenz unten.
  const tierBonus = tier === "sofort" ? 200 : tier === "plus30" ? 80 : 0;
  const score = (merchantMatch ? 1000 : 0) + tierBonus + (50 - Math.min(diffDays, 50));
  // EigenstΟΛndige (paarweise) Konfidenz βÄî die kontextbewusste Endeinstufung
  // erfolgt in assignPayPalLinks (berΟΦcksichtigt nΟΛhere Treffer derselben Zeile).
  const confidence = merchantMatch && tier !== "unklar" ? "hoch"
    : merchantMatch ? "niedrig"
    : tier === "sofort" ? "mittel" : "niedrig";
  return { diffDays, signedDays, tier, merchantMatch, score, confidence, refundVsDebit };
}

// Ordnet PayPal-Zeilen den Giro-Buchungen zu.
//  - links: sichere 1:1-Auto-VerknΟΦpfungen (fΟΦr Import).
//  - suggestions: alle Kandidatenpaare (fΟΦr die Vorschlagsansicht), bestes zuerst.
// Reihenfolge der Sicherheit: HΟΛndlername + βÄûsofort"-Timing ist am stΟΛrksten.
// Gibt es fΟΦr eine PayPal-Buchung einen nΟΛheren βÄûsofort"-Treffer, werden ihre
// weiter entfernten Kandidaten (z.B. der Folgemonat eines Abos) abgewertet.
export function assignPayPalLinks(newRows, giroTxs, linkDays, opts = {}) {
  const excludeRows = opts.excludeRows || new Set();
  const excludeGiroIds = opts.excludeGiroIds || new Set();

  const pairs = [];
  newRows.forEach((r, rowIdx) => {
    if (excludeRows.has(rowIdx)) return;
    // Internes Leg (PayPal-+30-Kauf oder Quell-Erstattung einer Auszahlung):
    // hat keine eigene Giro-Buchung (lΟΛuft ΟΦber die generische Abbuchung/
    // Auszahlung) βÜ£ nicht matchen.
    if (r._internalLeg) return;
    giroTxs.forEach(t => {
      if (excludeGiroIds.has(t.id)) return;
      const s = scoreMatch(r, t, linkDays);
      if (s) pairs.push({ rowIdx, giroTx: t, ...s });
    });
  });

  // ZΟΛhlungen. Der SchlΟΦssel zur Vereinfachung: Eindeutigkeit im ENGEN
  // Zeitfenster (tight = βÄûsofort"). Eine gleich hohe Buchung 30 Tage entfernt
  // macht einen Wenige-Tage-Treffer NICHT unsicher.
  const candByTx = {};
  const rowHasSofort = {};
  const tightByRow = {};
  const tightByTx = {};
  pairs.forEach(p => {
    candByTx[p.giroTx.id] = (candByTx[p.giroTx.id] || 0) + 1;
    if (p.tier === "sofort") {
      rowHasSofort[p.rowIdx] = true;
      tightByRow[p.rowIdx] = (tightByRow[p.rowIdx] || 0) + 1;
      tightByTx[p.giroTx.id] = (tightByTx[p.giroTx.id] || 0) + 1;
    }
  });

  // Kontextbewusste Konfidenz + verstΟΛndlicher Grund je Paar.
  pairs.forEach(p => {
    // Redundant: fΟΦr dieselbe PayPal-Buchung existiert ein nΟΛherer βÄûsofort"-Treffer.
    p.redundant = p.tier !== "sofort" && !!rowHasSofort[p.rowIdx];
    // Eindeutig im engen Fenster: genau ein Wenige-Tage-Treffer auf beiden Seiten.
    const tightUnique = tightByRow[p.rowIdx] === 1 && tightByTx[p.giroTx.id] === 1;
    if (p.redundant) {
      p.confidence = "niedrig";
      p.reason = "nΟΛherer Treffer vorhanden βÄ™ Belastung folgt normal in Tagen";
    } else if (p.tier === "sofort") {
      if (p.merchantMatch && tightUnique) {
        p.confidence = "hoch";
        p.reason = p.diffDays <= 1 ? "HΟΛndler + Belastung ~sofort" : `HΟΛndler + Belastung ${p.diffDays} Tage spΟΛter`;
      } else if (p.merchantMatch) {
        p.confidence = "hoch";
        p.reason = "HΟΛndlername stimmt ΟΦberein";
      } else if (tightUnique) {
        // Gleicher Betrag, Belastung wenige Tage spΟΛter, im engen Fenster
        // konkurrenzlos βÜ£ zuverlΟΛssig, auch ohne HΟΛndlernamen.
        p.confidence = "hoch";
        p.reason = `Betrag eindeutig, Belastung ${p.diffDays <= 1 ? "~sofort" : p.diffDays + " Tage spΟΛter"}`;
      } else {
        // Mehrere gleich hohe Buchungen IM engen Fenster βÜ£ Datum trennt nicht.
        p.confidence = "mittel";
        p.reason = "Betrag + wenige Tage, aber mehrere ΟΛhnliche Buchungen";
      }
    } else if (p.tier === "plus30") {
      if (p.merchantMatch) {
        p.confidence = "mittel";
        p.reason = `HΟΛndler, Belastung ${p.diffDays} Tage spΟΛter (evtl. PayPal +30)`;
      } else {
        p.confidence = "niedrig";
        p.reason = `nur Betrag, ${p.diffDays} Tage spΟΛter`;
      }
    } else {
      p.confidence = "niedrig";
      p.reason = `schwacher Treffer (${p.diffDays} Tage)`;
    }
    // Auto-verknΟΦpft wird, was zuverlΟΛssig ist: hoch, oder ein HΟΛndlertreffer.
    p.autoLinkable = p.confidence === "hoch" || (p.confidence === "mittel" && p.merchantMatch);
    // Erstattung βÜî Giro-Lastschrift: gegenlΟΛufige Vorzeichen sind nie sicher genug
    // fΟΦr eine Automatik βÄî nur als Vorschlag zum manuellen BestΟΛtigen anbieten.
    if (p.refundVsDebit) {
      p.autoLinkable = false;
      if (p.confidence === "hoch") p.confidence = "mittel";
      p.reason = "Erstattung zur Giro-Lastschrift (gleicher HΟΛndler)";
    }
  });

  // Saubere 1:1-Zuordnung als Vorschlagsliste: jede PayPal-Buchung und jede
  // Giro-Buchung hΟΕchstens einmal, stΟΛrkste Konfidenz zuerst, dann zeitlich am
  // nΟΛchsten. links = die automatisch sicheren Treffer daraus.
  const rank = c => (c === "hoch" ? 3 : c === "mittel" ? 2 : 1);
  const ranked = pairs
    .filter(p => !p.redundant)
    .sort((a, b) => rank(b.confidence) - rank(a.confidence) || a.diffDays - b.diffDays || b.score - a.score);
  const usedRows = new Set();
  const usedTx = new Set();
  const suggestions = [];
  const links = [];
  ranked.forEach(p => {
    if (usedRows.has(p.rowIdx) || usedTx.has(p.giroTx.id)) return;
    usedRows.add(p.rowIdx);
    usedTx.add(p.giroTx.id);
    suggestions.push(p);
    if (p.autoLinkable) links.push(p);
  });

  return { links, suggestions };
}
